def solve(weight: list[int]) -> int:
    n = len(weight)
    pre = [-1] * n
    stack = []
    for i in range(n):
        while stack and weight[stack[-1]] <= weight[i]:
            stack.pop()
        if stack:
            pre[i] = stack[-1]
        else:
            pre[i] = -1
        stack.append(i)

    count = 0
    start = 0
    for i in range(n):
        if i >= start:
            if pre[i] != -1 and pre[i] >= start:
                count += 1
                start = i + 1
    return count
